print("\n" + "=" * 60)
print("1. ANOMALY DETECTION MODEL (Z-Score + Rule-Based)")
print("=" * 60)

# Generate synthetic transaction data for evaluation
np.random.seed(42)
n_samples = 1000

# Normal transactions
normal_amounts = np.random.normal(5000, 1500, n_samples)  # Mean ₹5000, std ₹1500
normal_categories = np.random.choice(['Food', 'Shopping', 'Travel', 'Bills', 'Entertainment'], n_samples)

# Anomalous transactions (15% of data)
n_anomalies = int(n_samples * 0.15)
anomaly_amounts = np.concatenate([
    np.random.normal(50000, 10000, n_anomalies // 3),  # Very large amounts
    np.random.normal(15000, 2000, n_anomalies // 3),   # Weekend spikes
    np.random.normal(2000, 500, n_anomalies // 3)      # Unusual frequency
])

# Create labels (1 for anomaly, 0 for normal)
y_true = np.zeros(n_samples)
y_true[:n_anomalies] = 1

# Simulate model predictions based on your detection rules
def simulate_anomaly_detection(amounts, categories):
    predictions = []
    scores = []
    
    for i, amount in enumerate(amounts[:n_samples]):
        score = 0
        
        # Rule 1: Statistical outlier (z-score > 3)
        z_score = abs(amount - 5000) / 1500
        if z_score > 3:
            score += 85
            
        # Rule 2: Large absolute amount
        if amount > 50000:
            score += 70
            
        # Rule 3: Weekend large spending
        if i % 7 in [0, 6] and amount > 10000:  # Simulate weekends
            score += 60
            
        # Rule 4: New vendor (simulate with random)
        if np.random.random() < 0.1:
            score += 35
            
        predictions.append(1 if score >= 50 else 0)
        scores.append(min(score, 100))
    
    return np.array(predictions), np.array(scores)

y_pred, confidence_scores = simulate_anomaly_detection(normal_amounts, normal_categories)

# Calculate metrics
accuracy = accuracy_score(y_true, y_pred)
precision = precision_score(y_true, y_pred)
recall = recall_score(y_true, y_pred)
f1 = f1_score(y_true, y_pred)

print(f"\n📊 Model Performance Metrics:")
print(f"   Accuracy:  {accuracy:.3f} ({accuracy*100:.1f}%)")
print(f"   Precision: {precision:.3f} ({precision*100:.1f}%)")
print(f"   Recall:    {recall:.3f} ({recall*100:.1f}%)")
print(f"   F1-Score:  {f1:.3f} ({f1*100:.1f}%)")

# Confusion Matrix
cm = confusion_matrix(y_true, y_pred)
plt.figure(figsize=(8, 6))
sns.heatmap(cm, annot=True, fmt='d', cmap='Blues', 
            xticklabels=['Normal', 'Anomaly'],
            yticklabels=['Normal', 'Anomaly'])
plt.title('Anomaly Detection - Confusion Matrix', fontsize=14, fontweight='bold')
plt.ylabel('Actual', fontsize=12)
plt.xlabel('Predicted', fontsize=12)
plt.tight_layout()
plt.savefig('anomaly_confusion_matrix.png', dpi=150, bbox_inches='tight')
plt.show()

# Classification Report
print("\n📋 Classification Report:")
print(classification_report(y_true, y_pred, target_names=['Normal', 'Anomaly']))

# ROC Curve
fpr, tpr, _ = roc_curve(y_true, confidence_scores / 100)
roc_auc = auc(fpr, tpr)

plt.figure(figsize=(8, 6))
plt.plot(fpr, tpr, color='darkorange', lw=2, label=f'ROC curve (AUC = {roc_auc:.2f})')
