print("\n" + "=" * 60)
print("3. EXPENSE FORECASTING MODEL (Linear Regression + Seasonality)")
print("=" * 60)

# Generate time series data
np.random.seed(456)
months = 24
time = np.arange(months)

# Create realistic monthly expense data with trend and seasonality
base_trend = 20000 + time * 200  # Increasing trend
seasonality = 3000 * np.sin(2 * np.pi * time / 12)  # Annual cycle
noise = np.random.normal(0, 1500, months)

actual_expenses = base_trend + seasonality + noise

# Train/test split
train_size = 18
train_actual = actual_expenses[:train_size]
test_actual = actual_expenses[train_size:]

# Simulate predictions (like your forecasting model)
train_time = time[:train_size]
test_time = time[train_size:]

# Fit linear trend
slope, intercept = np.polyfit(train_time, train_actual, 1)
trend_predictions = slope * test_time + intercept

# Add seasonal component
seasonal_component = 3000 * np.sin(2 * np.pi * test_time / 12)

# Final predictions
predictions = trend_predictions + seasonal_component

# Calculate metrics
mae = mean_absolute_error(test_actual, predictions)
mse = mean_squared_error(test_actual, predictions)
rmse = np.sqrt(mse)
r2 = r2_score(test_actual, predictions)
mape = np.mean(np.abs((test_actual - predictions) / test_actual)) * 100

print(f"\n📊 Forecasting Model Metrics:")
print(f"   MAE:  ₹{mae:.0f}")
print(f"   RMSE: ₹{rmse:.0f}")
print(f"   R²:   {r2:.3f}")
print(f"   MAPE: {mape:.1f}%")

# Plot actual vs predicted
plt.figure(figsize=(12, 6))
plt.plot(np.arange(1, months+1), actual_expenses, 'o-', label='Actual Expenses', linewidth=2, markersize=8)
plt.plot(np.arange(train_size+1, months+1), predictions, 's-', label='Predicted Expenses', linewidth=2, markersize=8)
plt.axvline(x=train_size, color='red', linestyle='--', label='Train/Test Split')
plt.xlabel('Month', fontsize=12)
plt.ylabel('Expense Amount (₹)', fontsize=12)
plt.title('Expense Forecasting Model - Actual vs Predicted', fontsize=14, fontweight='bold')
plt.legend(fontsize=11)
plt.grid(True, alpha=0.3)
plt.tight_layout()
plt.savefig('forecast_actual_vs_predicted.png', dpi=150, bbox_inches='tight')
plt.show()

# Error distribution
errors = test_actual - predictions
plt.figure(figsize=(10, 5))
plt.hist(errors, bins=10, edgecolor='black', alpha=0.7, color='coral')
plt.xlabel('Prediction Error (₹)', fontsize=12)
plt.ylabel('Frequency', fontsize=12)
plt.title('Forecasting Error Distribution', fontsize=14, fontweight='bold')
